import torch
from torch import nn

class EWCPenalty:
    """Compute EWC loss term after training on prior task."""

    def __init__(self, model: nn.Module, dataloader, device: str = "cuda"):
        self.params = {n: p.clone().detach() for n, p in model.named_parameters() if p.requires_grad}
        self.fisher  = self._compute_fisher(model, dataloader, device)

    def _compute_fisher(self, model, dataloader, device):
        fisher = {n: torch.zeros_like(p) for n, p in model.named_parameters() if p.requires_grad}
        model.eval()
        for batch in dataloader:
            model.zero_grad()
            batch = {k: v.to(device) for k, v in batch.items()}
            output = model(**batch)
            output.loss.backward()
            for n, p in model.named_parameters():
                if p.requires_grad and p.grad is not None:
                    fisher[n] += p.grad.detach() ** 2
        # Normalise by number of batches
        n_batches = len(dataloader)
        for n in fisher:
            fisher[n] /= n_batches
        return fisher

    def penalty(self, model: nn.Module, lam: float = 1000.0) -> torch.Tensor:
        loss = torch.tensor(0.0, requires_grad=True)
        for n, p in model.named_parameters():
            if n in self.fisher:
                loss = loss + (self.fisher[n] * (p - self.params[n]) ** 2).sum()
        return (lam / 2) * loss

# Usage:
ewc = EWCPenalty(model, task_a_loader)
