import random

class ReservoirBuffer:
    """
    Fixed-size replay buffer using reservoir sampling.
    After seeing n total examples, every example has probability B/n
    of being in the buffer — regardless of when it arrived.
    """
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.buffer   = []
        self.seen     = 0

    def add(self, example):
        self.seen += 1
        if len(self.buffer) < self.capacity:
            self.buffer.append(example)
        else:
            # Replace a random position with probability capacity/seen
            idx = random.randint(0, self.seen - 1)
            if idx < self.capacity:
                self.buffer[idx] = example

    def sample(self, n: int) -> list:
        return random.choices(self.buffer, k=min(n, len(self.buffer)))

# Usage: as you stream task A training data, fill the buffer
buffer = ReservoirBuffer(capacity=10_000)
for example in task_a_stream:
    train_on(example)
    buffer.add(example)

# When training on task B, mix in reservoir samples
for batch in task_b_loader:
    replay_samples = buffer.sample(len(batch) // 5)  # 20% replay
    mixed_batch = batch + replay_samples
    train_on(mixed_batch)
